@app.route('/api/analytics/documents-by-status', methods=['GET'])
def documents_by_status():
    """Aggregate documents count by status."""
    pipeline = [
        {
            '$group': {
                '_id': '$status',
                'count': {'$sum': 1},
                'total_views': {'$sum': '$views'},
                'total_likes': {'$sum': '$likes'},
                'avg_views': {'$avg': '$views'}
            }
        },
        {
            '$project': {
                'status': '$_id',
                '_id': 0,
                'count': 1,
                'total_views': 1,
                'total_likes': 1,
                'avg_views': {'$round': ['$avg_views', 2]}
            }
        },
        {'$sort': {'count': -1}}
    ]

    result = list(documents_collection.aggregate(pipeline))
    return jsonify({'analytics': parse_json(result)}), 200


