@app.route('/api/analytics/content-quality', methods=['GET'])
def content_quality():
    """Analyze content quality metrics using engagement ratios."""
    pipeline = [
        {'$match': {'status': 'published', 'views': {'$gt': 0}}},
        {
            '$addFields': {
                'engagement_ratio': {
                    '$round': [
                        {'$multiply': [
                            {'$divide': ['$likes', '$views']},
                            100
                        ]},
                        2
                    ]
                }
            }
        },
        {
            '$bucket': {
                'groupBy': '$engagement_ratio',
                'boundaries': [0, 1, 5, 10, 25, 50, 100],
                'default': '100+',
                'output': {
                    'count': {'$sum': 1},
                    'avg_views': {'$avg': '$views'},
                    'avg_likes': {'$avg': '$likes'},
                    'documents': {
                        '$push': {
                            'title': '$title',
                            'engagement_ratio': '$engagement_ratio'
                        }
                    }
                }
            }
        }
    ]

    result = list(documents_collection.aggregate(pipeline))
    return jsonify({'content_quality': parse_json(result)}), 200


